public class MinIndex {
    static int minIndex(int[] arr) {
        int minIdx = -1;
        int minVal = Integer.MAX_VALUE;
        for (int i = 1; i < arr.length; i++) {   // bug: starts at 1, skips arr[0]
            if (arr[i] < minVal) { minVal = arr[i]; minIdx = i; }
        }
        return minIdx;
    }
}
